import type { Metadata } from "next";
import PosRegister from "./PosRegister";

export const metadata: Metadata = {
  title: "レジ会計 | ぐんじょうストア POS",
  description:
    "POS レジの会計画面。店舗・レジ番号・担当者・取引番号と取引ステータス（会計中 / 支払待ち / 完了 / 取消）のヘッダ、数量・単価・税率（10% / 軽減8%）・金額を編集できるカート明細、値引きと税率別内訳・消費税・合計を自動計算する金額サマリー、現金（預り金→おつり）/クレジット/電子マネー/QR/商品券の支払、会員・ポイント、会計確定 / 保留 / 取消、レシートプレビューと印刷を備えたレジ会計ツールです。",
};

export default function PosPage() {
  return <PosRegister />;
}

// POS register domain types + product catalog + money/tax math.
// Tax math is kept here (pure, no React) so it can be reasoned about in isolation.

export type TaxRate = 10 | 8

export interface Product {
  sku: string
  name: string
  unitPrice: number
  taxRate: TaxRate
  /** Coarse grouping for the quick-pick grid. */
  category: "food" | "drink" | "daily" | "other"
}

export interface CartLine {
  /** Stable per-line id (a SKU can appear once; qty handles repeats). */
  id: string
  sku: string
  name: string
  unitPrice: number
  taxRate: TaxRate
  qty: number
}

export type DiscountMode = "yen" | "percent"

export type PaymentMethod = "cash" | "credit" | "emoney" | "qr" | "voucher"

export type TxStatus = "in_progress" | "awaiting_payment" | "completed" | "voided"

export const PAYMENT_METHODS: { value: PaymentMethod; label: string }[] = [
  { value: "cash", label: "現金" },
  { value: "credit", label: "クレジット" },
  { value: "emoney", label: "電子マネー" },
  { value: "qr", label: "QRコード" },
  { value: "voucher", label: "商品券" },
]

export const PAYMENT_METHOD_LABEL: Record<PaymentMethod, string> = PAYMENT_METHODS.reduce(
  (acc, m) => ({ ...acc, [m.value]: m.label }),
  {} as Record<PaymentMethod, string>,
)

// A small but realistic スーパー catalog. 8% = 軽減税率 (飲食料品); 10% = 標準.
export const CATALOG: Product[] = [
  { sku: "4901", name: "おにぎり 鮭", unitPrice: 150, taxRate: 8, category: "food" },
  { sku: "4902", name: "サンドイッチ たまご", unitPrice: 320, taxRate: 8, category: "food" },
  { sku: "4903", name: "幕の内弁当", unitPrice: 580, taxRate: 8, category: "food" },
  { sku: "4904", name: "緑茶 500ml", unitPrice: 130, taxRate: 8, category: "drink" },
  { sku: "4905", name: "ブレンドコーヒー", unitPrice: 180, taxRate: 8, category: "drink" },
  { sku: "4906", name: "ビール 350ml", unitPrice: 230, taxRate: 10, category: "drink" },
  { sku: "4907", name: "レジ袋（大）", unitPrice: 5, taxRate: 10, category: "other" },
  { sku: "4908", name: "乾電池 単3 4本", unitPrice: 498, taxRate: 10, category: "daily" },
  { sku: "4909", name: "ボックスティッシュ", unitPrice: 298, taxRate: 10, category: "daily" },
  { sku: "4910", name: "歯ブラシ", unitPrice: 198, taxRate: 10, category: "daily" },
  { sku: "4911", name: "チョコレート", unitPrice: 160, taxRate: 8, category: "food" },
  { sku: "4912", name: "雑誌", unitPrice: 690, taxRate: 10, category: "other" },
]

export const QUICK_CASH = [1000, 5000, 10000] as const

// ---- Money / tax math (pure) -------------------------------------------------

export interface RateBucket {
  rate: TaxRate
  /** 税込でない、その税率対象の合計（税抜小計に相当する本体価格の集計）。*/
  taxable: number
  /** その税率の消費税額。*/
  tax: number
}

export interface CartTotals {
  /** 小計（税抜・値引き前の本体合計）。*/
  subtotal: number
  /** 値引き額（円）。*/
  discount: number
  /** 税率別内訳（値引き後・按分済み）。*/
  buckets: RateBucket[]
  /** 消費税合計。*/
  taxTotal: number
  /** 合計（お会計）= 小計 − 値引き + 消費税。*/
  total: number
  /** 商品点数（数量合計）。*/
  itemCount: number
}

export function lineAmount(line: Pick<CartLine, "unitPrice" | "qty">): number {
  return line.unitPrice * line.qty
}

/**
 * Compute totals with a correct per-rate tax breakdown.
 * Unit prices are treated as 税抜 (本体価格). A whole-order discount is
 * apportioned across rate buckets proportionally to each bucket's taxable
 * amount, then tax is computed per bucket and floored (Japanese rounding:
 * 端数切り捨て per 税率), matching how a register prints the 税率別内訳.
 */
export function computeTotals(
  lines: CartLine[],
  discount: { mode: DiscountMode; value: number },
): CartTotals {
  const subtotal = lines.reduce((sum, l) => sum + lineAmount(l), 0)
  const itemCount = lines.reduce((sum, l) => sum + l.qty, 0)

  const rawDiscount =
    discount.mode === "percent"
      ? Math.floor((subtotal * clampPercent(discount.value)) / 100)
      : Math.floor(discount.value || 0)
  const appliedDiscount = Math.min(Math.max(rawDiscount, 0), subtotal)

  // Sum taxable per rate (本体価格).
  const byRate = new Map<TaxRate, number>()
  for (const l of lines) {
    byRate.set(l.taxRate, (byRate.get(l.taxRate) ?? 0) + lineAmount(l))
  }

  const buckets: RateBucket[] = []
  for (const rate of [10, 8] as TaxRate[]) {
    const grossTaxable = byRate.get(rate) ?? 0
    if (grossTaxable === 0) continue
    // Apportion the discount proportionally; guard subtotal 0.
    const share = subtotal > 0 ? (grossTaxable / subtotal) * appliedDiscount : 0
    const taxable = Math.max(0, grossTaxable - share)
    const tax = Math.floor((taxable * rate) / 100)
    buckets.push({ rate, taxable: Math.round(taxable), tax })
  }

  const taxTotal = buckets.reduce((sum, b) => sum + b.tax, 0)
  const total = subtotal - appliedDiscount + taxTotal

  return { subtotal, discount: appliedDiscount, buckets, taxTotal, total, itemCount }
}

function clampPercent(v: number): number {
  if (!Number.isFinite(v)) return 0
  return Math.min(100, Math.max(0, v))
}

let seq = 0
export function makeLineId(sku: string): string {
  seq += 1
  return `${sku}-${seq}`
}

"use client"

import * as React from "react"
import {
  IconShoppingCart,
  IconReceipt,
  IconPrinter,
  IconCheck,
  IconUser,
  IconCash,
  IconPlus,
  IconTrash,
} from "@tabler/icons-react"
import {
  Card,
  CardHeader,
  CardTitle,
  CardContent,
  CardFooter,
  CardDescription,
  Badge,
  Button,
  Statistic,
  Separator,
  Alert,
  AlertTitle,
  AlertDescription,
  EditableDataTable,
  RevealSection,
  EmptyState,
  CurrencyInput,
  NumberInput,
  ToggleGroup,
  ToggleGroupItem,
  Select,
  Input,
  Label,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  formatCurrency,
  type EditableColumn,
} from "@gunjo/ui"

import {
  CATALOG,
  PAYMENT_METHODS,
  PAYMENT_METHOD_LABEL,
  QUICK_CASH,
  computeTotals,
  lineAmount,
  makeLineId,
  type CartLine,
  type DiscountMode,
  type PaymentMethod,
  type Product,
  type TxStatus,
} from "./pos-data"

const yen = (n: number) => formatCurrency(n, { maximumFractionDigits: 0 })

const STATUS_META: Record<TxStatus, { label: string; variant: "secondary" | "warning" | "success" | "destructive" }> = {
  in_progress: { label: "会計中", variant: "secondary" },
  awaiting_payment: { label: "支払待ち", variant: "warning" },
  completed: { label: "完了", variant: "success" },
  voided: { label: "取消", variant: "destructive" },
}

function nowStamp(): string {
  // Render-stable in this demo: fixed string avoids hydration mismatch.
  return "2026-06-23 14:32"
}

export default function PosRegister() {
  const [lines, setLines] = React.useState<CartLine[]>([])
  const [discountMode, setDiscountMode] = React.useState<DiscountMode>("yen")
  const [discountValue, setDiscountValue] = React.useState<number>(0)
  const [method, setMethod] = React.useState<PaymentMethod>("cash")
  const [tendered, setTendered] = React.useState<number | undefined>(undefined)
  const [memberOpen, setMemberOpen] = React.useState(false)
  const [memberNo, setMemberNo] = React.useState("")
  const [usePoints, setUsePoints] = React.useState<number | undefined>(undefined)
  const [status, setStatus] = React.useState<TxStatus>("in_progress")
  const [receiptOpen, setReceiptOpen] = React.useState(false)

  const txNo = "T-20260623-0042"

  const totals = React.useMemo(
    () => computeTotals(lines, { mode: discountMode, value: discountValue }),
    [lines, discountMode, discountValue],
  )

  const isCompleted = status === "completed"
  const isVoided = status === "voided"
  const editable = !isCompleted && !isVoided
  const isCash = method === "cash"
  // Change & shortfall only meaningful for cash.
  const change = isCash && tendered !== undefined ? tendered - totals.total : 0
  const cashShort = isCash && (tendered === undefined || tendered < totals.total)
  const hasLines = lines.length > 0

  // Earned points: 1pt / 100円 of 合計 (floor). Used points capped at total.
  const earnedPoints = Math.floor(totals.total / 100)
  const pointsAvailable = 320 // demo balance

  const blockReason: string | null = !hasLines
    ? "カートに商品がありません。"
    : isCash && cashShort
      ? `預り金が不足しています（不足額 ${yen(Math.max(0, totals.total - (tendered ?? 0)))}）。`
      : null

  const canCheckout = editable && hasLines && blockReason === null

  // ---- cart mutators --------------------------------------------------------
  const addProduct = React.useCallback((p: Product) => {
    setLines((prev) => {
      const existing = prev.find((l) => l.sku === p.sku)
      if (existing) {
        return prev.map((l) => (l.id === existing.id ? { ...l, qty: l.qty + 1 } : l))
      }
      return [
        ...prev,
        { id: makeLineId(p.sku), sku: p.sku, name: p.name, unitPrice: p.unitPrice, taxRate: p.taxRate, qty: 1 },
      ]
    })
    if (status === "awaiting_payment") setStatus("in_progress")
  }, [status])

  const setQty = (id: string, qty: number) =>
    setLines((prev) => prev.map((l) => (l.id === id ? { ...l, qty: Math.max(1, qty) } : l)))
  const removeLine = (index: number) => setLines((prev) => prev.filter((_, i) => i !== index))

  const resetAll = () => {
    setLines([])
    setDiscountValue(0)
    setDiscountMode("yen")
    setTendered(undefined)
    setMethod("cash")
    setStatus("in_progress")
    setMemberOpen(false)
    setMemberNo("")
    setUsePoints(undefined)
  }

  const handleCheckout = () => {
    if (!canCheckout) return
    setStatus("completed")
    setReceiptOpen(true)
  }
  const handleHold = () => {
    if (!hasLines) return
    setStatus("awaiting_payment")
  }
  const handleVoid = () => setStatus("voided")

  // ---- cart grid columns ----------------------------------------------------
  const columns: EditableColumn<CartLine>[] = [
    {
      id: "name",
      header: "商品名",
      minWidth: "11rem",
      cell: (row) => (
        <div className="flex flex-col gap-0.5">
          <span className="font-medium text-foreground">{row.name}</span>
          <span className="text-xs text-muted-foreground">
            {row.sku}
            {row.taxRate === 8 ? (
              <span className="ml-1 font-medium text-warning">※軽減8%</span>
            ) : null}
          </span>
        </div>
      ),
    },
    {
      id: "qty",
      header: "数量",
      align: "center",
      width: "8.5rem",
      cell: (row, ctx) => (
        <NumberInput
          layout="stepper"
          min={1}
          value={row.qty}
          onValueChange={(v) => setQty(row.id, v)}
          disabled={!editable}
          aria-label={ctx.ariaLabel}
          incrementLabel={`${row.name} の数量を増やす`}
          decrementLabel={`${row.name} の数量を減らす`}
          className="mx-auto"
        />
      ),
    },
    {
      id: "unit",
      header: "単価",
      align: "right",
      width: "7rem",
      cell: (row) => (
        <span className="tabular-nums text-muted-foreground">{yen(row.unitPrice)}</span>
      ),
    },
    {
      id: "rate",
      header: "税率",
      align: "center",
      width: "5rem",
      cell: (row) =>
        row.taxRate === 8 ? (
          <Badge variant="warning" as="span">
            8%<span className="sr-only"> 軽減税率</span>
          </Badge>
        ) : (
          <Badge variant="outline" as="span">
            10%
          </Badge>
        ),
    },
    {
      id: "amount",
      header: "金額",
      align: "right",
      width: "7rem",
      cell: (row) => (
        <span className="font-medium tabular-nums text-foreground">{yen(lineAmount(row))}</span>
      ),
    },
  ]

  return (
    <main className="mx-auto w-full max-w-6xl px-4 py-6 sm:px-6 lg:py-8">
      {/* ---- 会計ヘッダ ---- */}
      <header className="mb-6">
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div className="flex items-center gap-2">
            <span className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-primary-subtle text-primary-subtle-foreground">
              <IconShoppingCart className="h-5 w-5" aria-hidden="true" />
            </span>
            <div>
              <h1 className="text-2xl font-bold tracking-tight">レジ会計</h1>
              <p className="text-sm text-muted-foreground">ぐんじょうストア — POS レジ</p>
            </div>
          </div>
          <Badge variant={STATUS_META[status].variant} className="h-6 px-3 text-sm">
            <span className="sr-only">取引ステータス: </span>
            {STATUS_META[status].label}
          </Badge>
        </div>

        <dl className="mt-4 grid grid-cols-2 gap-x-4 gap-y-2 text-sm sm:grid-cols-4">
          <div>
            <dt className="text-xs text-muted-foreground">店舗</dt>
            <dd className="font-medium">新宿東口店</dd>
          </div>
          <div>
            <dt className="text-xs text-muted-foreground">レジ番号</dt>
            <dd className="font-medium tabular-nums">No.03</dd>
          </div>
          <div>
            <dt className="text-xs text-muted-foreground">担当者</dt>
            <dd className="font-medium">田中 美咲</dd>
          </div>
          <div>
            <dt className="text-xs text-muted-foreground">取引番号 / 日時</dt>
            <dd className="font-medium tabular-nums">
              {txNo}
              <span className="ml-1 font-normal text-muted-foreground">{nowStamp()}</span>
            </dd>
          </div>
        </dl>
      </header>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-[minmax(0,1fr)_22rem]">
        {/* ================= LEFT: cart + quick pick ================= */}
        <div className="flex flex-col gap-6">
          {/* quick product picker */}
          <Card>
            <CardHeader className="p-4 pb-2">
              <CardTitle as="h2" className="text-base">
                商品を追加
              </CardTitle>
              <CardDescription>タップで明細に追加。同一商品は数量が加算されます。</CardDescription>
            </CardHeader>
            <CardContent className="p-4 pt-2">
              <div className="grid grid-cols-2 gap-2 sm:grid-cols-3">
                {CATALOG.map((p) => (
                  <Button
                    key={p.sku}
                    type="button"
                    variant="outline"
                    onClick={() => addProduct(p)}
                    disabled={!editable}
                    className="h-auto flex-col items-start gap-0.5 px-3 py-2 text-left"
                  >
                    <span className="flex w-full items-center justify-between gap-1">
                      <span className="truncate text-sm font-medium">{p.name}</span>
                      {p.taxRate === 8 ? (
                        <span className="shrink-0 text-[10px] font-semibold text-warning">※8%</span>
                      ) : null}
                    </span>
                    <span className="text-xs font-normal text-muted-foreground tabular-nums">
                      {yen(p.unitPrice)}
                    </span>
                  </Button>
                ))}
              </div>
            </CardContent>
          </Card>

          {/* cart */}
          <Card>
            <CardHeader className="flex-row items-center justify-between p-4 pb-2">
              <CardTitle as="h2" className="text-base">
                カート明細
              </CardTitle>
              {hasLines ? (
                <span className="text-sm text-muted-foreground tabular-nums">
                  {totals.itemCount} 点
                </span>
              ) : null}
            </CardHeader>
            <CardContent className="p-4 pt-2">
              {hasLines ? (
                <EditableDataTable
                  columns={columns}
                  rows={lines}
                  getRowId={(row) => row.id}
                  onRemoveRow={editable ? removeLine : undefined}
                  rowLabel={(i) => `${i + 1}行目`}
                  labels={{
                    removeRow: (i) => `${i + 1}行目を削除`,
                  }}
                  caption="商品ごとの数量・単価・税率・金額"
                  renderFooterCell={(col) => {
                    if (col.id === "name") return "小計（税抜）"
                    if (col.id === "amount")
                      return <span className="tabular-nums">{yen(totals.subtotal)}</span>
                    return null
                  }}
                />
              ) : (
                <EmptyState
                  headingLevel={3}
                  icon={<IconShoppingCart className="h-6 w-6" aria-hidden="true" />}
                  title="カートは空です"
                  description="上の「商品を追加」から商品を選んで会計を始めます。"
                />
              )}
            </CardContent>
          </Card>
        </div>

        {/* ================= RIGHT: summary + payment ================= */}
        <div className="flex flex-col gap-6 lg:sticky lg:top-6 lg:self-start">
          {/* 金額サマリー */}
          <Card>
            <CardHeader className="p-4 pb-2">
              <CardTitle as="h2" className="text-base">
                金額サマリー
              </CardTitle>
            </CardHeader>
            <CardContent className="flex flex-col gap-3 p-4 pt-2">
              <Row label="小計（税抜）" value={yen(totals.subtotal)} />

              {/* 値引き controls */}
              <div className="flex flex-col gap-1.5">
                <Label htmlFor="discount-value">値引き（割引）</Label>
                <div className="flex items-center gap-2">
                  <ToggleGroup
                    type="single"
                    value={discountMode}
                    onValueChange={(v) => v && setDiscountMode(v as DiscountMode)}
                    disallowEmpty
                    variant="outline"
                    size="sm"
                    aria-label="値引きの種類"
                    className="shrink-0"
                  >
                    <ToggleGroupItem value="yen" aria-label="円で値引き">
                      ¥
                    </ToggleGroupItem>
                    <ToggleGroupItem value="percent" aria-label="パーセントで値引き">
                      %
                    </ToggleGroupItem>
                  </ToggleGroup>
                  {discountMode === "yen" ? (
                    <CurrencyInput
                      id="discount-value"
                      value={discountValue || undefined}
                      min={0}
                      max={totals.subtotal}
                      onValueChange={(v) => setDiscountValue(v ?? 0)}
                      disabled={!editable || !hasLines}
                      aria-label="値引き額（円）"
                    />
                  ) : (
                    <div className="flex w-full items-center gap-1">
                      <NumberInput
                        id="discount-value"
                        value={discountValue}
                        min={0}
                        max={100}
                        onValueChange={(v) => setDiscountValue(v)}
                        disabled={!editable || !hasLines}
                        aria-label="値引き率（パーセント）"
                      />
                      <span className="text-sm text-muted-foreground">%</span>
                    </div>
                  )}
                </div>
              </div>

              {totals.discount > 0 ? (
                <Row label="値引き" value={`− ${yen(totals.discount)}`} tone="discount" />
              ) : null}

              <Separator />

              {/* 税率別内訳 */}
              <div className="flex flex-col gap-1.5">
                <p className="text-xs font-medium text-muted-foreground">税率別内訳</p>
                {totals.buckets.length ? (
                  totals.buckets.map((b) => (
                    <div key={b.rate} className="flex flex-col gap-0.5">
                      <Row
                        label={`${b.rate}% 対象${b.rate === 8 ? "（軽減）" : ""}`}
                        value={yen(b.taxable)}
                        small
                      />
                      <Row label={`　消費税 (${b.rate}%)`} value={yen(b.tax)} small muted />
                    </div>
                  ))
                ) : (
                  <p className="text-sm text-muted-foreground">—</p>
                )}
                <Row label="消費税合計" value={yen(totals.taxTotal)} />
              </div>

              <Separator />

              <Statistic
                label="合計（お会計）"
                value={yen(totals.total)}
                hint={hasLines ? `税込 / ${totals.itemCount} 点` : undefined}
              />
            </CardContent>
          </Card>

          {/* 支払 */}
          <Card>
            <CardHeader className="p-4 pb-2">
              <CardTitle as="h2" className="text-base">
                支払
              </CardTitle>
            </CardHeader>
            <CardContent className="flex flex-col gap-3 p-4 pt-2">
              <div className="flex flex-col gap-1.5">
                <span id="pay-method-label" className="text-sm font-medium">
                  支払方法
                </span>
                <ToggleGroup
                  type="single"
                  value={method}
                  onValueChange={(v) => v && setMethod(v as PaymentMethod)}
                  disallowEmpty
                  variant="outline"
                  aria-labelledby="pay-method-label"
                  className="flex-wrap justify-start"
                >
                  {PAYMENT_METHODS.map((m) => (
                    <ToggleGroupItem key={m.value} value={m.value} disabled={!editable}>
                      {m.label}
                    </ToggleGroupItem>
                  ))}
                </ToggleGroup>
              </div>

              {/* 現金のみ: 預り金 + おつり + クイック金額 */}
              <RevealSection open={isCash} label="現金の預り金とおつり" className="flex flex-col gap-3">
                <div className="flex flex-col gap-1.5">
                  <Label htmlFor="tendered">預り金</Label>
                  <CurrencyInput
                    id="tendered"
                    value={tendered}
                    min={0}
                    onValueChange={setTendered}
                    disabled={!editable || !hasLines}
                    aria-invalid={hasLines && cashShort}
                    aria-describedby="change-line"
                  />
                  <div className="flex flex-wrap gap-1.5">
                    {QUICK_CASH.map((amt) => (
                      <Button
                        key={amt}
                        type="button"
                        variant="secondary"
                        size="sm"
                        disabled={!editable || !hasLines}
                        onClick={() => setTendered((prev) => (prev ?? 0) + amt)}
                      >
                        +{yen(amt)}
                      </Button>
                    ))}
                    <Button
                      type="button"
                      variant="secondary"
                      size="sm"
                      disabled={!editable || !hasLines}
                      onClick={() => setTendered(totals.total)}
                    >
                      ちょうど
                    </Button>
                  </div>
                </div>

                <div
                  id="change-line"
                  className="flex items-center justify-between rounded-lg border border-border bg-muted/40 px-3 py-2"
                >
                  <span className="text-sm font-medium">おつり</span>
                  <span
                    className={`text-lg font-bold tabular-nums ${cashShort ? "text-muted-foreground" : "text-success"}`}
                  >
                    {cashShort ? "—" : yen(change)}
                  </span>
                </div>
              </RevealSection>

              {/* non-cash hint */}
              <RevealSection open={!isCash && hasLines} label={`${PAYMENT_METHOD_LABEL[method]}での支払`}>
                <Alert variant="info">
                  <IconCash className="h-4 w-4" aria-hidden="true" />
                  <AlertTitle as="p">{PAYMENT_METHOD_LABEL[method]}で会計します</AlertTitle>
                  <AlertDescription>
                    端末で {yen(totals.total)} を処理してから「会計確定」を押してください。
                  </AlertDescription>
                </Alert>
              </RevealSection>

              {/* blocked reason (announced) */}
              {blockReason ? (
                <Alert variant={isCash && cashShort && hasLines ? "warning" : "info"} aria-live="polite">
                  <AlertTitle as="p">{isCash && cashShort && hasLines ? "現金不足" : "会計できません"}</AlertTitle>
                  <AlertDescription>{blockReason}</AlertDescription>
                </Alert>
              ) : null}

              {isCompleted ? (
                <Alert variant="success" aria-live="polite">
                  <IconCheck className="h-4 w-4" aria-hidden="true" />
                  <AlertTitle as="p">会計完了</AlertTitle>
                  <AlertDescription>
                    {PAYMENT_METHOD_LABEL[method]}で {yen(totals.total)} を受領
                    {isCash && tendered !== undefined ? `（おつり ${yen(Math.max(0, change))}）` : ""}。
                  </AlertDescription>
                </Alert>
              ) : null}
            </CardContent>
          </Card>

          {/* 会員・ポイント */}
          <Card>
            <CardHeader className="flex-row items-center justify-between p-4 pb-2">
              <CardTitle as="h2" className="text-base">
                会員・ポイント
              </CardTitle>
              <Button
                type="button"
                variant="ghost"
                size="sm"
                onClick={() => setMemberOpen((v) => !v)}
                aria-expanded={memberOpen}
                disabled={!editable}
              >
                <IconUser className="h-4 w-4" aria-hidden="true" />
                {memberOpen ? "閉じる" : "会員を読み取る"}
              </Button>
            </CardHeader>
            <RevealSection open={memberOpen} label="会員情報とポイント">
              <CardContent className="flex flex-col gap-3 p-4 pt-2">
                <div className="flex flex-col gap-1.5">
                  <Label htmlFor="member-no">会員番号</Label>
                  <Input
                    id="member-no"
                    inputMode="numeric"
                    placeholder="例: 9001-2345-6789"
                    value={memberNo}
                    onChange={(e) => setMemberNo(e.target.value)}
                    disabled={!editable}
                  />
                </div>
                <div className="grid grid-cols-2 gap-2 text-sm">
                  <div className="rounded-lg border border-border px-3 py-2">
                    <p className="text-xs text-muted-foreground">利用可能</p>
                    <p className="font-bold tabular-nums">{pointsAvailable} pt</p>
                  </div>
                  <div className="rounded-lg border border-border px-3 py-2">
                    <p className="text-xs text-muted-foreground">今回付与</p>
                    <p className="font-bold tabular-nums text-success">+{earnedPoints} pt</p>
                  </div>
                </div>
                <div className="flex flex-col gap-1.5">
                  <Label htmlFor="use-points">利用ポイント</Label>
                  <Select
                    id="use-points"
                    value={String(usePoints ?? 0)}
                    onChange={(e) => setUsePoints(Number(e.target.value) || undefined)}
                    disabled={!editable}
                  >
                    <option value="0">使用しない</option>
                    <option value="100">100 pt 使用</option>
                    <option value="200">200 pt 使用</option>
                    <option value={String(pointsAvailable)}>全部使用（{pointsAvailable} pt）</option>
                  </Select>
                </div>
              </CardContent>
            </RevealSection>
          </Card>

          {/* アクション */}
          <Card>
            <CardContent className="flex flex-col gap-2 p-4">
              {isVoided ? (
                <Button type="button" variant="outline" onClick={resetAll} className="w-full">
                  新規取引を開始
                </Button>
              ) : isCompleted ? (
                <>
                  <Button
                    type="button"
                    variant="outline"
                    onClick={() => setReceiptOpen(true)}
                    className="w-full"
                  >
                    <IconReceipt className="h-4 w-4" aria-hidden="true" />
                    レシートを表示
                  </Button>
                  <Button type="button" variant="primary" onClick={resetAll} className="w-full">
                    <IconPlus className="h-4 w-4" aria-hidden="true" />
                    次の取引へ
                  </Button>
                </>
              ) : (
                <>
                  <Button
                    type="button"
                    variant="success"
                    onClick={handleCheckout}
                    disabled={!canCheckout}
                    aria-describedby={blockReason ? "checkout-block" : undefined}
                    className="w-full"
                  >
                    <IconCheck className="h-4 w-4" aria-hidden="true" />
                    会計確定 {hasLines ? yen(totals.total) : ""}
                  </Button>
                  {blockReason ? (
                    <p id="checkout-block" className="text-xs text-muted-foreground">
                      {blockReason}
                    </p>
                  ) : null}
                  <div className="flex gap-2">
                    <Button
                      type="button"
                      variant="outline"
                      onClick={handleHold}
                      disabled={!hasLines}
                      className="flex-1"
                    >
                      保留
                    </Button>
                    <Button
                      type="button"
                      variant="destructive"
                      onClick={handleVoid}
                      disabled={!hasLines}
                      className="flex-1"
                    >
                      <IconTrash className="h-4 w-4" aria-hidden="true" />
                      取消
                    </Button>
                  </div>
                </>
              )}
            </CardContent>
          </Card>
        </div>
      </div>

      {/* ---- レシート preview ---- */}
      <ReceiptDialog
        open={receiptOpen}
        onOpenChange={setReceiptOpen}
        lines={lines}
        totals={totals}
        method={method}
        tendered={tendered}
        change={change}
        txNo={txNo}
        stamp={nowStamp()}
      />
    </main>
  )
}

// ---- helper row -------------------------------------------------------------
function Row({
  label,
  value,
  tone,
  small,
  muted,
}: {
  label: React.ReactNode
  value: React.ReactNode
  tone?: "discount"
  small?: boolean
  muted?: boolean
}) {
  return (
    <div className="flex items-baseline justify-between gap-2">
      <span className={`${small ? "text-xs" : "text-sm"} ${muted ? "text-muted-foreground" : ""}`}>
        {label}
      </span>
      <span
        className={`tabular-nums ${small ? "text-xs" : "text-sm font-medium"} ${
          tone === "discount" ? "text-destructive" : muted ? "text-muted-foreground" : ""
        }`}
      >
        {value}
      </span>
    </div>
  )
}

// ---- receipt ----------------------------------------------------------------
function ReceiptDialog({
  open,
  onOpenChange,
  lines,
  totals,
  method,
  tendered,
  change,
  txNo,
  stamp,
}: {
  open: boolean
  onOpenChange: (v: boolean) => void
  lines: CartLine[]
  totals: ReturnType<typeof computeTotals>
  method: PaymentMethod
  tendered: number | undefined
  change: number
  txNo: string
  stamp: string
}) {
  const isCash = method === "cash"
  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-sm">
        <DialogHeader>
          <DialogTitle>レシート</DialogTitle>
          <DialogDescription>会計内容の控えです。印刷またはお客様控えにご利用ください。</DialogDescription>
        </DialogHeader>

        <div className="max-h-[60vh] overflow-y-auto rounded-md border border-border bg-card p-4 font-mono text-xs leading-relaxed text-card-foreground">
          <div className="text-center">
            <p className="text-sm font-bold">ぐんじょうストア 新宿東口店</p>
            <p className="text-muted-foreground">レジ No.03 / 担当 田中</p>
            <p className="text-muted-foreground">{txNo}　{stamp}</p>
          </div>
          <div className="my-2 border-t border-dashed border-border" />
          <ul className="flex flex-col gap-1">
            {lines.map((l) => (
              <li key={l.id} className="flex justify-between gap-2">
                <span className="truncate">
                  {l.taxRate === 8 ? "※" : "　"}
                  {l.name} ×{l.qty}
                </span>
                <span className="shrink-0 tabular-nums">{yen(lineAmount(l))}</span>
              </li>
            ))}
          </ul>
          <div className="my-2 border-t border-dashed border-border" />
          <div className="flex justify-between">
            <span>小計</span>
            <span className="tabular-nums">{yen(totals.subtotal)}</span>
          </div>
          {totals.discount > 0 ? (
            <div className="flex justify-between">
              <span>値引き</span>
              <span className="tabular-nums">− {yen(totals.discount)}</span>
            </div>
          ) : null}
          {totals.buckets.map((b) => (
            <div key={b.rate} className="flex justify-between text-muted-foreground">
              <span>
                {b.rate}% 対象 {yen(b.taxable)}（税 {yen(b.tax)}）
              </span>
              <span />
            </div>
          ))}
          <div className="flex justify-between">
            <span>消費税</span>
            <span className="tabular-nums">{yen(totals.taxTotal)}</span>
          </div>
          <div className="my-1 border-t border-border" />
          <div className="flex justify-between text-sm font-bold">
            <span>合計</span>
            <span className="tabular-nums">{yen(totals.total)}</span>
          </div>
          <div className="mt-1 flex justify-between">
            <span>お支払い（{PAYMENT_METHOD_LABEL[method]}）</span>
            <span className="tabular-nums">{yen(isCash ? (tendered ?? 0) : totals.total)}</span>
          </div>
          {isCash ? (
            <div className="flex justify-between">
              <span>おつり</span>
              <span className="tabular-nums">{yen(Math.max(0, change))}</span>
            </div>
          ) : null}
          <p className="mt-3 text-center text-muted-foreground">※印は軽減税率(8%)対象</p>
          <p className="text-center text-muted-foreground">ありがとうございました</p>
        </div>

        <DialogFooter>
          <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
            閉じる
          </Button>
          <Button type="button" variant="primary" onClick={() => window.print()}>
            <IconPrinter className="h-4 w-4" aria-hidden="true" />
            印刷
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}
